import React from 'react'
import Head from 'next/head'
import fetch from 'isomorphic-unfetch'

const Home = ({ data }) => {
  let weekNum = 1
  console.log(data[`week-${weekNum}`]);

  const nextWeek = () => {
    weekNum += 1;
  }


  return(
    <div>

      <Head>
        <title>Home</title>
        <link rel="icon" href="" />
      </Head>

      <button onClick={nextWeek} />

      {/* {data.map((day, i) => (
        <div key={i}>
          <h1>{day.label}</h1>
          <p>{day.exercise}</p>
        </div>
      ))} */}

    </div>
  )
}

Home.getInitialProps = async () => {
  const res = await fetch('http://localhost:3000/api/daily')
  const json = await res.json()

  return { data: json }
}

export default Home
